void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;
vUv = 0.5 + (vUv-0.5)*1.5;
vec2 rotate_uv = 0.5+uv_rotate(0 + (vUv-0.5)*uAspect.xy, 0, q3, q4, 2);
vec2 bipolar_uv = uv_bipolar(rotate_uv,vec2(0,0.5),vec2(1,0.5), 2, 0.35, vec2(q11,q12));
vec2 mirror_uv = 0.5 + (0.5 - abs( fract( bipolar_uv * 0.5 ) * 2.0 - 1.0 ));
vUv = mirror_uv;
    vec2 uv_grid=vUv+0.03*vec2(sin(vUv.y*31+0.59*uTime),sin(vUv.x*26+0.37*uTime));
    ret = texture(sampler_main, vUv).xyz;
